function dingerEraRange(era) {
  const match = String(era).match(/^(\d{4})[–-](\d{4}|present)$/);
  if (!match) return null;
  return { start: Number(match[1]), end: match[2] === 'present' ? 'present' : Number(match[2]) };
}

function dingerDecade(year) {
  return `${Math.floor(year / 10) * 10}s`;
}

function dingerEraWindow(era) {
  const range = dingerEraRange(era);
  if (!range) return 'Career window comes from a deeper baseball era';
  const start = dingerDecade(range.start);
  const end = range.end === 'present' ? 'today' : dingerDecade(range.end);
  return `Career window sits in the ${start === end ? start : `${start} to ${end}`} range`;
}

function dingerCareerStart(era) {
  const range = dingerEraRange(era);
  return range ? `Career began in ${range.start}` : 'Career start belongs to the historical record';
}

function dingerCareerEnd(era) {
  const range = dingerEraRange(era);
  if (!range) return 'Career ending belongs to the historical record';
  return range.end === 'present' ? 'Career is still marked active in this puzzle set' : `Career ended in ${range.end}`;
}

function dingerCuratedId(rawId) {
  return String(rawId).toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, '').replace(/[^a-z0-9]+/g, '');
}

